18	
19	package resolver
20	
21	import (
22		"encoding/base64"
23		"iter"
24		"sort"
25		"strings"
26	)
27	
28	type addressMapEntry[T any] struct {
29		addr  Address
30		value T
31	}
32	
33	// AddressMap is an AddressMapV2[any].  It will be deleted in an upcoming
34	// release of grpc-go.
35	//
36	// Deprecated: use the generic AddressMapV2 type instead.
37	type AddressMap = AddressMapV2[any]
38	
39	// AddressMapV2 is a map of addresses to arbitrary values taking into account
40	// Attributes.  BalancerAttributes are ignored, as are Metadata and Type.
41	// Multiple accesses may not be performed concurrently.  Must be created via
42	// NewAddressMap; do not construct directly.
43	type AddressMapV2[T any] struct {
44		// The underlying map is keyed by an Address with fields that we don't care
45		// about being set to their zero values. The only fields that we care about
46		// are `Addr`, `ServerName` and `Attributes`. Since we need to be able to
47		// distinguish between addresses with same `Addr` and `ServerName`, but
48		// different `Attributes`, we cannot store the `Attributes` in the map key.
49		//
50		// The comparison operation for structs work as follows:
51		//  Struct values are comparable if all their fields are comparable. Two
52		//  struct values are equal if their corresponding non-blank fields are equal.
53		//
54		// The value type of the map contains a slice of addresses which match the key
55		// in their `Addr` and `ServerName` fields and contain the corresponding value
56		// associated with them.
57		m map[Address]addressMapEntryList[T]
58	}
59	
60	func toMapKey(addr *Address) Address {
61		return Address{Addr: addr.Addr, ServerName: addr.ServerName}
62	}
63	
64	type addressMapEntryList[T any] []*addressMapEntry[T]
65	
66	// NewAddressMap creates a new AddressMapV2[any].
67	//
68	// Deprecated: use the generic NewAddressMapV2 constructor instead.
69	func NewAddressMap() *AddressMap {
70		return NewAddressMapV2[any]()
71	}
72	
73	// NewAddressMapV2 creates a new AddressMapV2.
74	func NewAddressMapV2[T any]() *AddressMapV2[T] {
75		return &AddressMapV2[T]{m: make(map[Address]addressMapEntryList[T])}
76	}
77	
78	// find returns the index of addr in the addressMapEntry slice, or -1 if not
79	// present.
80	func (l addressMapEntryList[T]) find(addr Address) int {
81		for i, entry := range l {
82			// Attributes are the only thing to match on here, since `Addr` and
83			// `ServerName` are already equal.
84			if entry.addr.Attributes.Equal(addr.Attributes) {
85				return i
86			}
87		}
88		return -1
89	}
90	
91	// Get returns the value for the address in the map, if present.
92	func (a *AddressMapV2[T]) Get(addr Address) (value T, ok bool) {
93		addrKey := toMapKey(&addr)
94		entryList := a.m[addrKey]
95		if entry := entryList.find(addr); entry != -1 {
96			return entryList[entry].value, true
97		}
98		return value, false
99	}
100	
101	// Set updates or adds the value to the address in the map.
102	func (a *AddressMapV2[T]) Set(addr Address, value T) {
103		addrKey := toMapKey(&addr)
104		entryList := a.m[addrKey]
105		if entry := entryList.find(addr); entry != -1 {
106			entryList[entry].value = value
107			return
108		}
109		a.m[addrKey] = append(entryList, &addressMapEntry[T]{addr: addr, value: value})
110	}
111	
112	// Delete removes addr from the map.
113	func (a *AddressMapV2[T]) Delete(addr Address) {
114		addrKey := toMapKey(&addr)
115		entryList := a.m[addrKey]
116		entry := entryList.find(addr)
117		if entry == -1 {
118			return
119		}
120		if len(entryList) == 1 {
121			entryList = nil
122		} else {
123			copy(entryList[entry:], entryList[entry+1:])
124			entryList = entryList[:len(entryList)-1]
125		}
126		a.m[addrKey] = entryList
127	}
128	
129	// Len returns the number of entries in the map.
130	func (a *AddressMapV2[T]) Len() int {
131		ret := 0
132		for _, entryList := range a.m {
133			ret += len(entryList)
134		}
135		return ret
136	}
137	
138	// Keys returns a slice of all current map keys.
139	// Deprecated: Use AddressMapV2.All() instead.
140	func (a *AddressMapV2[T]) Keys() []Address {
141		ret := make([]Address, 0, a.Len())
142		for _, entryList := range a.m {
143			for _, entry := range entryList {
144				ret = append(ret, entry.addr)
145			}
146		}
147		return ret
148	}
149	
150	// Values returns a slice of all current map values.
151	// Deprecated: Use AddressMapV2.All() instead.
152	func (a *AddressMapV2[T]) Values() []T {
153		ret := make([]T, 0, a.Len())
154		for _, entryList := range a.m {
155			for _, entry := range entryList {
156				ret = append(ret, entry.value)
157			}
158		}
159		return ret
160	}
161	
162	// All returns an iterator over all elements.
163	func (a *AddressMapV2[T]) All() iter.Seq2[Address, T] {
164		return func(yield func(Address, T) bool) {
165			for _, entryList := range a.m {
166				for _, entry := range entryList {
167					if !yield(entry.addr, entry.value) {
168						return
169					}
170				}
171			}
172		}
173	}
174	
175	type endpointMapKey string
176	
177	// EndpointMap is a map of endpoints to arbitrary values keyed on only the
178	// unordered set of address strings within an endpoint. This map is not thread
179	// safe, thus it is unsafe to access concurrently. Must be created via
180	// NewEndpointMap; do not construct directly.
181	type EndpointMap[T any] struct {
182		endpoints map[endpointMapKey]endpointData[T]
183	}
184	
185	type endpointData[T any] struct {
186		// decodedKey stores the original key to avoid decoding when iterating on
187		// EndpointMap keys.
188		decodedKey Endpoint
189		value      T
190	}
191	
192	// NewEndpointMap creates a new EndpointMap.
193	func NewEndpointMap[T any]() *EndpointMap[T] {
194		return &EndpointMap[T]{
195			endpoints: make(map[endpointMapKey]endpointData[T]),
196		}
197	}
198	
199	// encodeEndpoint returns a string that uniquely identifies the unordered set of
200	// addresses within an endpoint.
201	func encodeEndpoint(e Endpoint) endpointMapKey {
202		addrs := make([]string, 0, len(e.Addresses))
203		// base64 encoding the address strings restricts the characters present
204		// within the strings. This allows us to use a delimiter without the need of
205		// escape characters.
206		for _, addr := range e.Addresses {
207			addrs = append(addrs, base64.StdEncoding.EncodeToString([]byte(addr.Addr)))
208		}
209		sort.Strings(addrs)
210		// " " should not appear in base64 encoded strings.
211		return endpointMapKey(strings.Join(addrs, " "))
212	}
213	
214	// Get returns the value for the address in the map, if present.
215	func (em *EndpointMap[T]) Get(e Endpoint) (value T, ok bool) {
216		val, found := em.endpoints[encodeEndpoint(e)]
217		if found {
218			return val.value, true
219		}
220		return value, false
221	}
222	
223	// Set updates or adds the value to the address in the map.
224	func (em *EndpointMap[T]) Set(e Endpoint, value T) {
225		en := encodeEndpoint(e)
226		em.endpoints[en] = endpointData[T]{
227			decodedKey: Endpoint{Addresses: e.Addresses},
228			value:      value,
229		}
230	}
231	
232	// Len returns the number of entries in the map.
233	func (em *EndpointMap[T]) Len() int {
234		return len(em.endpoints)
235	}
236	
237	// Keys returns a slice of all current map keys, as endpoints specifying the
238	// addresses present in the endpoint keys, in which uniqueness is determined by
239	// the unordered set of addresses. Thus, endpoint information returned is not
240	// the full endpoint data (drops duplicated addresses and attributes) but can be
241	// used for EndpointMap accesses.
242	// Deprecated: Use EndpointMap.All() instead.
243	func (em *EndpointMap[T]) Keys() []Endpoint {
244		ret := make([]Endpoint, 0, len(em.endpoints))
245		for _, en := range em.endpoints {
246			ret = append(ret, en.decodedKey)
247		}
248		return ret
249	}
250	
251	// Values returns a slice of all current map values.
252	// Deprecated: Use EndpointMap.All() instead.
253	func (em *EndpointMap[T]) Values() []T {
254		ret := make([]T, 0, len(em.endpoints))
255		for _, val := range em.endpoints {
256			ret = append(ret, val.value)
257		}
258		return ret
259	}
260	
261	// All returns an iterator over all elements.
262	// The map keys are endpoints specifying the addresses present in the endpoint
263	// map, in which uniqueness is determined by the unordered set of addresses.
264	// Thus, endpoint information returned is not the full endpoint data (drops
265	// duplicated addresses and attributes) but can be used for EndpointMap
266	// accesses.
267	func (em *EndpointMap[T]) All() iter.Seq2[Endpoint, T] {
268		return func(yield func(Endpoint, T) bool) {
269			for _, en := range em.endpoints {
270				if !yield(en.decodedKey, en.value) {
271					return
272				}
273			}
274		}
275	}
276	
277	// Delete removes the specified endpoint from the map.
278	func (em *EndpointMap[T]) Delete(e Endpoint) {
279		en := encodeEndpoint(e)
280		delete(em.endpoints, en)
281	}
